module RefModule (
    input wire clk,
    input wire rstn,
    input wire en,
    input wire up_dn,
    output reg [3:0] count
);

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or negedge rstn or posedge dbg_halt) begin
    if (!rstn)
        count <= 4'b0000;
    else if (en) begin
        if (up_dn)
            count <= count + 1'b1;
        else
            count <= count - 1'b1;
    end
end

endmodule
